def tri_bulles(nombres):
    items = list(nombres)
    for i in range(len(items)):
        for j in range(len(items) - 1 - i):
            if items[j] > items[j + 1]:
                items[j], items[j + 1] = items[j + 1], items[j]
    return items

def recherche_dichotomique(items, cible):
    gauche, droite = 0, len(items) - 1
    while gauche <= droite:
        milieu = (gauche + droite) // 2
        if items[milieu] == cible:
            return milieu
        if items[milieu] < cible:
            gauche = milieu + 1
        else:
            droite = milieu - 1
    return -1

